export const apiBase =
  process.env.NEXT_PUBLIC_API_BASE_URL || "https://xcustompackaging.com";

type FetchOpts = {
  revalidate?: number | false;
};

async function fetchJson(path: string, opts?: FetchOpts): Promise<any> {
  const url = `${apiBase}${path.startsWith("/") ? "" : "/"}${path}`;
  const init =
    typeof opts?.revalidate === "number"
      ? { next: { revalidate: opts.revalidate } }
      : { cache: "no-store" as const };
  const res = await fetch(url, init);
  if (!res.ok) return null;
  try {
    return await res.json();
  } catch {
    return null;
  }
}

export type Brand = {
  _id: string;
  name?: string;
  title?: string;
  slug: string;
  metaTitle?: string;
  metaDescription?: string;
  keywords?: string;
  bannerImage?: string;
  image?: string;
  robots?: string;
  faqImage?: string;
  faqImageAltText?: string;
};

export type Category = {
  _id: string;
  title?: string;
  slug: string;
  image?: string;
  metaTitle?: string;
  metaDescription?: string;
  keywords?: string;
  robots?: string;
  brandId?: { _id?: string; slug?: string; name?: string };
};

export type Product = {
  _id: string;
  name?: string;
  slug: string;
  description?: string;
  images?: { url?: string }[];
  metaTitle?: string;
  metaDescription?: string;
  keywords?: string;
  robots?: string;
  brandId?: { slug?: string; name?: string };
  categoryId?: { slug?: string; title?: string };
};

export type Blog = {
  _id: string;
  title?: string;
  slug: string;
  content?: string;
  image?: string;
  metaTitle?: string;
  metaDescription?: string;
  keywords?: string;
  robots?: string;
  qna?: Array<{ question: string; answer: string }>;
};

export type FaqItem = {
  question?: string;
  answer?: string;
};

export async function apiGet(path: string, opts?: FetchOpts): Promise<any> {
  return fetchJson(path, opts);
}

export async function getBrandsAll(
  revalidate: number = 3600
): Promise<Brand[]> {
  const r = await fetchJson("/brands/getAll", { revalidate });
  return Array.isArray(r?.data) ? r.data : [];
}

export async function getBrandBySlug(
  slug: string,
  revalidate: number = 600
): Promise<Brand | null> {
  const r = await fetchJson(`/brands/get?slug=${slug}`, { revalidate });
  return r?.data || null;
}

