export async function getCategoryProducts(
  categoryId: string,
  page?: number,
  revalidate: number = 600
): Promise<Product[]> {
  const qp = page ? `?page=${page}` : "";
  const r = await fetchJson(`/products/categoryProducts/${categoryId}${qp}`, {
    revalidate,
  });
  return Array.isArray(r?.data) ? r.data : [];
}

